// ═══════════════════════════════════════════════════════════════════════════════
//  CURRICULUM CATALOG — 50+ ülkenin resmi eğitim müfredatı (sınıf × ders × konu)
//
//  Yapı:
//    _curriculum[country][levelGradeKey][subjectKey] = [topic1, topic2, ...]
//
//  levelGradeKey formatı:
//    primary_1 .. primary_6 | middle_5 .. middle_10 | high_9 .. high_12
//    high_11_{track} | high_12_{track}
//    university_{grade} | masters | doctorate
//
//  Kaynaklar (Jan 2026 bilgi güncelliği):
//    • Türkiye — MEB Talim ve Terbiye Kurulu (ttkb.meb.gov.tr) resmi müfredat
//    • ABD — Common Core State Standards (corestandards.org) + NGSS
//    • İngiltere — GOV.UK National Curriculum + GCSE/A-Level AQA, OCR
//    • Almanya — Kultusministerkonferenz (KMK) + Abitur Bildungsstandards
//    • Fransa — Éducation Nationale + programmes du Baccalauréat
//    • Japonya — MEXT Course of Study (学習指導要領)
//    • Çin — 人民教育出版社 (People's Education Press) Gaokao müfredatı
//    • Güney Kore — Ministry of Education + 수능 (Suneung) subjects
//    • Hindistan — NCERT + CBSE + CISCE
//    • Kanada — provincial curricula (Ontario, Quebec, British Columbia)
//    • Diğer ülkeler — UNESCO IBE + WorldData Education Systems
//
//  NOT: Bu katalog uygulama içi çevrimdışı çalışır; Firestore'a da replikası
//  atılabilir (config/curriculum/{country}) — böylece dönem değişikliklerinde
//  OTA güncelleme mümkün.
// ═══════════════════════════════════════════════════════════════════════════════

import 'package:flutter/material.dart' show Color;
import 'education_profile.dart';

class CurriculumSubject {
  /// _allSubjects kataloğundaki anahtar ile aynı
  final String key;

  /// Ekranda gösterilecek isim (ülkenin dili; örn. "Matematik", "数学", "الرياضيات")
  final String displayName;

  /// Derse özel emoji
  final String emoji;

  /// Bu sınıf/dönem için müfredatta yer alan konu başlıkları
  final List<String> topics;

  const CurriculumSubject({
    required this.key,
    required this.displayName,
    required this.emoji,
    required this.topics,
  });
}

/// Eğitim profiline göre o dönem okutulan dersleri + konularını döndürür.
///
/// Arama sırası:
///   1) Tam eşleşme  (country_level_grade[_track])
///   2) Track'sız fallback (country_level_grade)
///   3) Seviye fallback (country_level)
///   4) Uluslararası şablon (international_level)
///   5) Son çare: generic primary/middle/high varsayılanı
List<CurriculumSubject> curriculumFor(EduProfile? profile) {
  if (profile == null) return _fallbackByLevel(null);

  // 0) AI tarafından bu profil için runtime'da üretilmiş ülke-spesifik
  //    müfredat varsa onu kullan (static catalog 30 ülke; bu kademe
  //    geri kalan 100+ ülkeyi AI ile karşılar).
  final aiTopics = EduProfile.aiCachedTopics(profile);
  final aiSubjects = EduProfile.aiCachedSubjects(profile);
  if (aiTopics != null &&
      aiTopics.isNotEmpty &&
      aiSubjects != null &&
      aiSubjects.isNotEmpty) {
    final result = <CurriculumSubject>[];
    for (final s in aiSubjects) {
      final topics = aiTopics[s.key] ?? const <String>[];
      result.add(CurriculumSubject(
        key: s.key,
        displayName: s.name,
        emoji: s.emoji,
        topics: topics,
      ));
    }
    if (result.isNotEmpty) return result;
  }

  // 1-4) Static catalog lookup zinciri.
  final keys = _lookupKeys(profile);
  final intlKey = 'international_${profile.level}';
  for (final k in keys) {
    // Sınav profilinde 'international_exam_prep' JENERİK şablonuna düşmeden
    // önce sınav-spesifik köprü (aşağıda) denenmeli — jenerik şablon TUS
    // seçen kullanıcıya lise dersleri gösterirdi.
    if (profile.level == 'exam_prep' && k == intlKey) continue;
    final found = _curriculum[k];
    if (found != null) return _materialize(found, profile.country);
  }

  // 4.5) SINAV PROFİLİ KÖPRÜSÜ — statik katalogda '<ülke>_exam_prep_<sınav>'
  // girişi olmayan sınavlar (TUS/DUS/EUS, MIR, OAB, Advokatexamen… tüm
  // meslek sınavları ve yerel adlı sınavlar) için education_profile'daki
  // evrensel sınav→ders sınıflayıcısından DOĞRU ders listesi kurulur.
  // Konular AI müfredat önbelleği dolunca zenginleşir (onboarding prefetch /
  // education_setup fetch); o ana kadar konu listesi boş olabilir ama
  // DERSLER sınava uygundur (anatomi/cerrahi, anayasa/ceza hukuku vb.).
  if (profile.level == 'exam_prep') {
    final subs = subjectsForProfile(profile);
    if (subs.isNotEmpty) {
      return [
        for (final s in subs)
          CurriculumSubject(
            key: s.key,
            displayName: s.name,
            emoji: s.emoji,
            topics: aiTopics?[s.key] ?? const <String>[],
          ),
      ];
    }
    final intl = _curriculum[intlKey];
    if (intl != null) return _materialize(intl, profile.country);
  }

  // 5) Son çare: international_${level} ya da international_high.
  return _fallbackByLevel(profile.level);
}

List<String> _lookupKeys(EduProfile p) {
  final c = p.country.toLowerCase();
  final l = p.level;
  final rawGrade = p.grade;
  // Grade normalize:
  //  • Sayısal sınıf ("9. Sınıf" / "11. Klasse" / "Grade 9") → "9".
  //  • Sınav adı ("YKS (Yükseköğretim...)" / "LGS" / "MSÜ") → ilk kelime
  //    lower-cased ASCII (örn. "yks", "lgs", "msu"). Önceden katalog
  //    "tr_exam_prep_yks" anahtarını arıyor ama g = "YKS (Yükse...)"
  //    olduğundan eşleşmiyor; YKS profili boş konuya düşüyordu.
  final m = RegExp(r'(\d{1,2})').firstMatch(rawGrade);
  String g;
  String? gFull; // çok kelimeli sınav adları için birleşik anahtar
  if (m != null) {
    g = m.group(1)!;
  } else {
    String norm(String s) => s
        .toLowerCase()
        .replaceAll('ı', 'i')
        .replaceAll('ö', 'o')
        .replaceAll('ü', 'u')
        .replaceAll('ş', 's')
        .replaceAll('ç', 'c')
        .replaceAll('ğ', 'g')
        .replaceAll(RegExp(r'[^a-z0-9_]'), '');
    final tokens = rawGrade.trim().split(RegExp(r'\s+'));
    g = norm(tokens.first);
    if (g.isEmpty) g = rawGrade; // emniyet
    // "KPSS Ortaöğretim" → 'kpss_ortaogretim' — yalnız ilk kelimeye bakmak
    // 'tr_exam_prep_kpss'e düşürüyordu, kpss_ortaogretim girişi hiç
    // eşleşmiyordu. Parantezli açıklamalar ('YKS (Yükseköğretim…)') tam
    // anahtar üretmez, zararsızca ilk-kelime anahtarına düşer.
    if (tokens.length > 1 && !rawGrade.contains('(')) {
      final joined =
          tokens.map(norm).where((t) => t.isNotEmpty).join('_');
      if (joined != g && joined.isNotEmpty) gFull = joined;
    }
  }
  final t = p.track;
  return [
    if (t != null) '${c}_${l}_${g}_$t',
    if (gFull != null) '${c}_${l}_$gFull',
    '${c}_${l}_$g',
    '${c}_$l',
    'international_$l',
  ];
}

List<CurriculumSubject> _materialize(
  Map<String, List<String>> subjectToTopics,
  String country,
) {
  final result = <CurriculumSubject>[];
  for (final entry in subjectToTopics.entries) {
    final subj = _displayForSubject(entry.key, country);
    result.add(CurriculumSubject(
      key: entry.key,
      displayName: subj.name,
      emoji: subj.emoji,
      topics: entry.value,
    ));
  }
  return result;
}

class _SubjectDisplay {
  final String name;
  final String emoji;
  const _SubjectDisplay(this.name, this.emoji);
}

/// Ders key'inden ülkenin dilinde görsel ad döndürür.
_SubjectDisplay _displayForSubject(String key, String country) {
  final countryMap = _subjectDisplayOverrides[country];
  if (countryMap != null && countryMap[key] != null) return countryMap[key]!;
  // Generic fallback from shared subject names
  return _subjectDisplayDefaults[key] ??
      _SubjectDisplay(key, '📚');
}

/// Ülkeye göre son çare varsayılanlar (kataloğa girmemiş ülke/seviye için).
List<CurriculumSubject> _fallbackByLevel(String? level) {
  final key = 'international_${level ?? 'high'}';
  final found = _curriculum[key];
  if (found != null) return _materialize(found, 'international');
  return _materialize(_curriculum['international_high']!, 'international');
}

