// ═══════════════════════════════════════════════════════════════════════════════
//  AI PROMPT YARDIMCISI — profilden müfredat bağlamını kısa metne dönüştür
// ═══════════════════════════════════════════════════════════════════════════════

/// Gemini/OpenAI system prompt'una inject edilen "öğrenci hangi dersleri
/// görüyor?" bağlamı. AI bu bilgiyle soruları öğrencinin seviyesine özgü çözer.
String curriculumContextForPrompt(EduProfile? profile) {
  final subs = curriculumFor(profile);
  if (subs.isEmpty) return '';
  final lines = <String>['[CURRICULUM CONTEXT]'];
  lines.add('Student profile: ${profile?.displayLabel() ?? 'unknown'}');
  lines.add('Currently studying these subjects and topics:');
  for (final s in subs.take(10)) {
    final topics = s.topics.take(6).join(', ');
    lines.add('• ${s.displayName}: $topics${s.topics.length > 6 ? '…' : ''}');
  }
  lines.add('Use these topics as context: pick the exact grade-appropriate terminology, assumptions, and depth when solving questions.');
  return lines.join('\n');
}

/// CurriculumSubject → EduSubject dönüştürücüsü.
/// Renkler key bazlı belirlenir; bilinmeyen key → varsayılan mavi.
List<EduSubject> curriculumSubjectsForProfile(EduProfile profile) {
  final subs = curriculumFor(profile);
  if (subs.isEmpty) return const [];
  return subs.map((c) {
    return EduSubject(c.key, c.emoji, c.displayName, _colorForKey(c.key));
  }).toList();
}

Color _colorForKey(String key) {
  // Renk paleti — yaygın ders kategorileri.
  const blue = Color(0xFF3B82F6);
  const purple = Color(0xFF8B5CF6);
  const red = Color(0xFFEF4444);
  const amber = Color(0xFFF59E0B);
  const green = Color(0xFF10B981);
  const brown = Color(0xFF92400E);
  const teal = Color(0xFF14B8A6);
  const indigo = Color(0xFF6366F1);
  const pink = Color(0xFFEC4899);
  const slate = Color(0xFF64748B);
  switch (key) {
    case 'math':
    case 'mathematics':
      return blue;
    case 'physics':
    case 'phys':
      return purple;
    case 'chem':
    case 'chemistry':
      return amber;
    case 'bio':
    case 'biology':
      return green;
    case 'history':
    case 'hist':
      return brown;
    case 'geo':
    case 'geography':
      return teal;
    case 'lit':
    case 'turkish':
    case 'lang_native':
      return red;
    case 'ingilizce':
    case 'english':
      return indigo;
    case 'religion':
      return teal;
    case 'felsefe':
    case 'philosophy':
      return purple;
    case 'sosyal':
    case 'sosyal_bilgiler':
      return amber;
    case 'fen':
    case 'fen_bilimleri':
      return green;
    case 'hayat':
    case 'hayat_bilgisi':
      return pink;
    case 'art_music':
    case 'sanat':
    case 'gorsel_sanatlar':
      return pink;
    case 'muzik':
      return red;
    case 'pe':
    case 'beden':
      return slate;
    case 'insan_haklari':
      return indigo;
    case 'trafik':
      return amber;
    case 'btya':
      return indigo;
    case 'inkilap':
      return red;
    case 'saglik_trafik':
      return amber;
    default:
      return blue;
  }
}

/// curriculum_catalog'u education_profile'a bir kez bağlar.
/// main.dart bunu başlangıçta çağırır.
void initCurriculumCatalog() {
  registerCurriculumContextBuilder(curriculumContextForPrompt);
  registerCurriculumSubjectsBuilder(curriculumSubjectsForProfile);
}
